// getBreakClassFromData looks up the line break class for a rune using binary search
func getBreakClassFromData(r rune) (BreakClass, bool) {
	// Binary search
	low, high := 0, len(lineBreakData)-1
	for low <= high {
		mid := (low + high) / 2
		if r < lineBreakData[mid].start {
			high = mid - 1
		} else if r > lineBreakData[mid].end {
			low = mid + 1
		} else {
			return lineBreakData[mid].class, true
		}
	}
	return ClassXX, false // Not found
}
